import Navigation from "../components/Navigation";
import Davigation from "../components/interactions/_navigation";

const Home = () => {
    return (
        <div className="home bg-img-custom">
            <Navigation />
            <Davigation />
            <section className="logo-section bg-img-custom"></section>
        </div>
    );
}

export default Home;
